<template>
  <div class="home recycle-scroller-demo">
    <div class="tool-bar">
      <button @mousedown="addOneTalkMsg">addOneTalkMsg</button>
      <button @mousedown="addOneHistory">addOneHistory</button>
      <button @mousedown="resetAll">resetAll</button>
      <input v-model="pageMode"
        type="checkbox" /> page mode
    </div>
    <RecycleScroller :items="list"
      key-field="id"
      ref="scroller"
      class="talk_list"
      @resize="resize"
      :page-mode="pageMode"
      :buffer="50"
      :item-height="132">
      <!-- , index, active -->
      <div slot-scope="{ item }"
        class="user">
        {{item}}
        <!-- {{index}}{{active}} -->
      </div>
    </RecycleScroller>
  </div>
</template>

<script>
// @ is an alias to /src

export default {
  name: 'home',
  data () {
    const list = new Array(10).fill(null).map((v, i) => ({ id: i, a: i }))
    return {
      list,
      pageMode: false
    }
  },
  components: {
  },
  mounted () {
    console.log(this)
  },
  methods: {
    resize (...data) {
      console.log(data)
    },
    resetAll () {
      this.list = []
    },
    addOneTalkMsg () {
      this.list.unshift({
        a: 1,
        b: 2 + this.list.length,
        id: this.list.length
      })
      this.$nextTick(() => {
        this.$refs.scroller.scrollTop = 0
      })
    },
    addOneHistory () {
      this.list.push({
        a: 1,
        b: 2,
        id: this.list.length
      })
    }
  }
}
</script>
<style lang="less" scoped>
  .user {
    padding: 0 12px;
    display: flex;
    align-items: center;
    transform: rotate(180deg);
  }
  .talk_list {
    transform: rotate(180deg);
  }
</style>
